import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos, guardarProducto } from '../services/productoService';

const Inventario = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [busqueda, setBusqueda] = useState(''); 
    const [editandoId, setEditandoId] = useState(null);
    const [nuevoProd, setNuevoProd] = useState({
        codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas'
    });

    const matricula = localStorage.getItem('usuarioLogueado') || 'desconocido';
    const rol = localStorage.getItem('rolUsuario') || 'VENDEDOR';
    const esAdmin = rol === 'ADMIN';

    useEffect(() => {
        const sesionActiva = localStorage.getItem('usuarioLogueado');
        if (!sesionActiva) {
            alert("⚠️ Acceso denegado. Por favor, inicia sesión.");
            navigate("/"); 
        } else {
            cargarProductos();
        }
    }, [navigate]);

    const cargarProductos = async () => {
        const data = await obtenerProductos();
        setProductos(data);
    };

    const productosFiltrados = productos.filter(p => 
        p.nombre.toLowerCase().includes(busqueda.toLowerCase()) || 
        p.codigo.toLowerCase().includes(busqueda.toLowerCase())
    );

    const prepararEdicion = (p) => {
        setEditandoId(p.id);
        setNuevoProd({
            codigo: p.codigo,
            nombre: p.nombre,
            stock: p.stock,
            precioCompra: p.precioCompra,
            precioVenta: p.precioVenta,
            categoria: p.categoria
        });
    };

    const handleGuardar = async (e) => {
        e.preventDefault();
        if (!esAdmin) return;
        
        const productoData = { 
            ...nuevoProd, 
            id: editandoId, 
            registradoPorMatricula: matricula
        };
        
        await guardarProducto(productoData);
        alert(editandoId ? "✅ Producto actualizado" : "✅ Producto guardado");
        
        setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });
        setEditandoId(null);
        cargarProductos();
    };

    const handleLogout = () => {
        localStorage.removeItem('usuarioLogueado');
        localStorage.removeItem('rolUsuario');
        navigate("/");
    };

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
                <div>
                    <h2>📦 Inventario - Isla Tecnológica</h2>
                    <span style={{ 
                        fontSize: '13px', 
                        background: esAdmin ? '#007bff' : '#28a745', 
                        color: 'white', 
                        padding: '3px 10px', 
                        borderRadius: '20px',
                        fontWeight: 'bold'
                    }}>
                        {esAdmin ? '🔑 Admin' : '👤 Vendedor'}: {matricula}
                    </span>
                </div>
                
                <div style={{ display: 'flex', gap: '10px' }}>
                    {/* Solo ADMIN ve estas opciones */}
                    {esAdmin && (
                        <>
                            <button 
                                onClick={() => navigate("/reportes")} 
                                style={{ backgroundColor: '#6f42c1', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold' }}
                            >
                                📈 Ver Ganancias
                            </button>
                            <button 
                                onClick={() => navigate("/usuarios")} 
                                style={{ backgroundColor: '#e67e22', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold' }}
                            >
                                👥 Usuarios
                            </button>
                        </>
                    )}

                    <button 
                        onClick={() => navigate("/ventas")} 
                        style={{ backgroundColor: '#28a745', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer', fontWeight: 'bold' }}
                    >
                        🛒 Ir a Ventas (Cobrar)
                    </button>

                    <button 
                        onClick={handleLogout} 
                        style={{ backgroundColor: '#dc3545', color: 'white', padding: '10px 15px', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
                    >
                        Cerrar Sesión
                    </button>
                </div>
            </div>

            {/* Formulario solo visible para ADMIN */}
            {esAdmin && (
                <form onSubmit={handleGuardar} style={{ marginBottom: '30px', border: '1px solid #ccc', padding: '15px', borderRadius: '8px', backgroundColor: editandoId ? '#fff3cd' : '#f8f9fa' }}>
                    <h3>{editandoId ? "✏️ Editando Producto" : "➕ Agregar Nuevo Producto"}</h3>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
                        <input placeholder="Código" value={nuevoProd.codigo} onChange={e => setNuevoProd({...nuevoProd, codigo: e.target.value})} required style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc' }} />
                        <input placeholder="Nombre" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} required style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc', flex: 1 }} />
                        <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: parseInt(e.target.value)})} required style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc', width: '80px' }} />
                        <input type="number" step="0.01" placeholder="Costo Compra" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({...nuevoProd, precioCompra: parseFloat(e.target.value)})} required style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc', width: '120px' }} />
                        <input type="number" step="0.01" placeholder="Precio Venta" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({...nuevoProd, precioVenta: parseFloat(e.target.value)})} required style={{ padding: '8px', borderRadius: '5px', border: '1px solid #ccc', width: '120px' }} />
                    </div>
                    
                    <div style={{ marginTop: '15px' }}>
                        <button type="submit" style={{ backgroundColor: editandoId ? '#ffc107' : '#28a745', color: 'black', cursor: 'pointer', padding: '10px 25px', border: 'none', borderRadius: '5px', fontWeight: 'bold' }}>
                            {editandoId ? "Actualizar Producto" : "Guardar Producto"}
                        </button>
                        
                        {editandoId && (
                            <button type="button" onClick={() => { setEditandoId(null); setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' }) }} style={{ marginLeft: '10px', padding: '10px', cursor: 'pointer', border: '1px solid #ccc', borderRadius: '5px' }}>
                                Cancelar
                            </button>
                        )}
                    </div>
                </form>
            )}

            <div style={{ marginBottom: '20px' }}>
                <input 
                    type="text" 
                    placeholder="🔍 Buscar por nombre o código..." 
                    value={busqueda}
                    onChange={(e) => setBusqueda(e.target.value)}
                    style={{ padding: '12px', width: '100%', borderRadius: '8px', border: '2px solid #007bff', fontSize: '16px' }}
                />
            </div>

            <table width="100%" style={{ textAlign: 'left', borderCollapse: 'collapse', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' }}>
                <thead style={{ backgroundColor: '#007bff', color: 'white' }}>
                    <tr>
                        <th style={{ padding: '12px' }}>Código</th>
                        <th>Nombre</th>
                        <th>Stock</th>
                        {esAdmin && <th>Costo ($)</th>}
                        <th>Venta ($)</th>
                        {esAdmin && <th>Ganancia ($)</th>}
                        {esAdmin && <th>Acciones</th>}
                    </tr>
                </thead>
                <tbody>
                    {productosFiltrados.map(p => (
                        <tr key={p.id} style={{ borderBottom: '1px solid #eee' }}>
                            <td style={{ padding: '12px' }}>{p.codigo}</td>
                            <td>{p.nombre}</td>
                            <td style={{ color: p.stock < 5 ? 'red' : 'black', fontWeight: p.stock < 5 ? 'bold' : 'normal' }}>{p.stock}</td>
                            {esAdmin && <td>${p.precioCompra.toFixed(2)}</td>}
                            <td>${p.precioVenta.toFixed(2)}</td>
                            {esAdmin && (
                                <td style={{ fontWeight: 'bold', color: 'green' }}>
                                    ${(p.precioVenta - p.precioCompra).toFixed(2)}
                                </td>
                            )}
                            {esAdmin && (
                                <td>
                                    <button onClick={() => prepararEdicion(p)} style={{ backgroundColor: '#007bff', color: 'white', border: 'none', padding: '5px 12px', borderRadius: '5px', cursor: 'pointer' }}>
                                        Editar
                                    </button>
                                </td>
                            )}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Inventario;
